'''This is a test template which is not yet to be used.'''
<cite style="font-style:normal" {{if
  |1={{{Ref|}}}
  |2={{ifnone
       |1={{{Ref}}}
       |2=
       |3=id="{{{Ref}}}"
     }}
  |3={{if
       |1={{{Surname|{{{Last|{{{Surname1|{{{Last1}}}}}}}}}}}}
       |2=id="HARV{{{Surname1|{{{Last1|{{{Surname|{{{Last}}}}}}}}}}}}{{{Surname2|{{{Last2|}}}}}}{{{Surname3|{{{Last3|}}}}}}{{{Surname4|{{{Last4|}}}}}}{{{Year}}}"
     }}
}}>{{if
  |{{{Surname|{{{Last|{{{Surname1|{{{Last1|{{{Author|{{{Author1}}}}}}}}}}}}}}}}}}
  |{{if
     |{{{Authorlink|{{{Authorlink1|}}}}}}
     |{{wikilink
        |{{{Authorlink1|{{{Authorlink}}}}}}
        |{{{Author1|{{{Author
            |{{{Surname1|{{{Last1|{{{Surname|{{{Last}}}}}}}}}}}}{{if
               |{{{Given|{{{First|{{{Given1|{{{First1|{{{Initials|{{{Initials1|}}}}}}}}}}}}}}}}}}
               |, {{{Initials1|{{{Given1|{{{First1|{{{Initials|{{{Given|{{{First}}}}}}}}}}}}}}}}}}
             }}
         }}}}}}
      }}
     |{{{Author1|{{{Author
         |{{{Surname1|{{{Last1|{{{Surname|{{{Last}}}}}}}}}}}}{{if
            |{{{Given|{{{First|{{{Given1|{{{First1|{{{Initials|{{{Initials1}}}}}}}}}}}}}}}}}}
            |, {{{Initials1|{{{Given1|{{{First1|{{{Initials|{{{Given|{{{First}}}}}}}}}}}}}}}}}}
          }}
      }}}}}}
   }}{{if
     |{{{Surname2|{{{Last2|{{{Author2|}}}}}}}}}
     |{{if
        |{{{Author3|{{{Surname3|{{{Last3|}}}}}}}}}
        |,&#32;
        |&#32;&amp;&#32;
      }}{{if
        |{{{Authorlink2|}}}
        |{{wikilink
          |{{{Authorlink2}}}
          |{{{Author2|{{{Surname2|{{{Last2|}}}}}}{{if|{{{Given2|{{{First2|{{{Initials2|}}}}}}}}}|, {{{Initials2|{{{Given2|{{{First2}}}}}}}}}}}}}}
         }}
        |{{{Author2|{{{Surname2|{{{Last2|}}}}}}{{if|{{{Given2|{{{First2|{{{Initials2|}}}}}}}}}|, {{{Initials2|{{{Given2|{{{First2}}}}}}}}}}}}}}
      }}{{if
        |{{{Surname3|{{{Last3|{{{Author3|}}}}}}}}}
        |&#32;&amp; {{if
           |{{{Authorlink3|}}}
           |{{wikilink
             |{{{Authorlink3}}}
             |{{{Author3|{{{Surname3|{{{Last3|}}}}}}{{if|{{{Given3|{{{First3|{{{Initials3|}}}}}}}}}|, {{{Initials3|{{{Given3|{{{First3}}}}}}}}}}}}}}
            }}
           |{{{Author3|{{{Surname3|{{{Last3|}}}}}}{{if|{{{Given3|{{{First3|{{{Initials3|}}}}}}}}}|, {{{Initials3|{{{Given3|{{{First3}}}}}}}}}}}}}}
         }}{{if
           |{{{Surname4|{{{Last4|{{{Author4|}}}}}}}}}
           |, et al.
         }}
      }}
   }}
  |…
}} ({{{Year}}}){{if
  |1={{{Journal|{{{Periodical|}}}}}}
  |2={{if
       |1={{{Title|}}}
       |2=, {{Link|1={{{URL|}}}|2="{{{Title}}}"}}
     }}, ''{{{Journal|{{{Periodical}}}}}}''{{if
       |{{{Volume|}}}
       |, vol. {{{Volume}}}
     }}{{if
       |{{{Issue|{{{Number|}}}}}}
       |, no. {{{Number|{{{Issue}}}}}}
     }}{{if
       |{{{Pages|}}}
       |, pp. {{{Pages}}}
       |{{if
          |{{{Page|}}}
          |, p. {{{Page}}}
        }}
     }}
  |3={{if
       |1={{{Chapter|{{{Contribution|}}}}}}
       |2={{if
            |1={{{Title|}}}
            |2=, {{Link|1={{{URL|}}}|2="{{{Title}}}"}}
          }}, "{{{Chapter|{{{Contribution}}}}}}" in {{if
            |{{{Editor|}}}
            |{{{Editor}}}, ed.,&#32;
          }}{{{Title}}}{{if
              |{{{Edition|}}}
              |&#32;({{{Edition}}} ed.)
          }}{{if
              |{{{Publisher|}}}
              |, {{{Publisher}}}
          }}{{if
              |{{{Place|}}}
              |, {{{Place}}}
          }}{{if
              |{{{ISBN|{{{ID|}}}}}}
              |, {{{ID|ISBN {{{ISBN}}}}}}
          }}{{if
            |{{{Pages|}}}
            |, pp. {{{Pages}}}
            |{{if
               |{{{Page|}}}
               |, p. {{{Page}}}
             }}
          }}
       |3={{if
            |1={{{Title|}}}
            |2=, {{Link|1={{{URL|}}}|2=''{{{Title}}}''}}
          }}{{if
              |{{{Edition|}}}
              |&#32;({{{Edition}}} ed.)
          }}{{if
              |{{{Publisher|}}}
              |, {{{Publisher}}}
          }}{{if
              |{{{Place|}}}
              |, {{{Place}}}
          }}{{if
              |{{{ISBN|{{{ID|}}}}}}
              |, {{{ID|ISBN {{{ISBN}}}}}}
          }}
     }}
}}{{if
    |{{{Access-date|}}}
    |&#32;<nowiki>[</nowiki>{{{Access-date}}}<nowiki>]</nowiki>
}}</cite>

