          |test={{{Page|}}}
          |then=, p. {{{Page}}}
        }}
     }}
  |else={{qif
       |test={{{Chapter|{{{Contribution|}}}}}}
       |then=, {{Link|1={{{URL|}}}|2="{{{Chapter|{{{Contribution}}}}}}"}} in {{qif
            |test={{{Editor|}}}
            |then={{{Editor}}}, ed.,&#32;
          }}''{{{Title}}}''{{qif
              |test={{{Edition|}}}
              |then=&#32;({{{Edition}}} ed.)
          }}{{qif
              |test={{{Publisher|}}}
              |then=, {{{Publisher}}}
          }}{{qif
              |test={{{Place|}}}
              |then=, {{{Place}}}
          }}{{qif
              |test={{{ISBN|{{{ID|}}}}}}
              |then=, {{{ID|ISBN {{{ISBN}}}}}}
          }}{{qif
            |test={{{Pages|}}}
            |then=, pp. {{{Pages}}}
            |else={{qif
               |test={{{Page|}}}
               |then=, p. {{{Page}}}
             }}
          }}
       |else={{qif
            |test={{{Title|}}}
            |then=, {{Link|1={{{URL|}}}|2=''{{{Title}}}''}}
          }}{{qif
              |test={{{Edition|}}}
              |then=&#32;({{{Edition}}} ed.)
          }}{{qif
              |test={{{Publisher|}}}
              |then=, {{{Publisher}}}
          }}{{qif
              |test={{{Place|}}}
              |then=, {{{Place}}}
          }}{{qif
              |test={{{ISBN|{{{ID|}}}}}}
              |then=, {{{ID|ISBN {{{ISBN}}}}}}
          }}
     }}
}}{{qif
